descriptor.templateCss:
:host {
    display: block;
    width: 100%;
    height: 100%;
    padding: 0;
    margin: 0;
}

.sensor-container {
    font-family: 'Roboto', Arial, sans-serif;
    background-color: transparent;
    width: 100%;
    height: 100%;
    box-sizing: border-box;
    padding: 8px;
}

.metric-card {
    background-color: #ffffff;
    border-radius: 8px;
    padding: 10px;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 4px;
    border-left: 4px solid #EE7623;
    transition: box-shadow 0.2s ease, border-left-color 0.2s ease;
    height: 100%;
    box-sizing: border-box;
    overflow: hidden;
    position: relative;
}

.metric-card.clickable {
    cursor: pointer;
}

.metric-card.clickable:hover {
    border-left-color: #ff8c42;
}

.main-content {
    flex: 1;
    display: flex;
    flex-direction: row;
    align-items: center;
    justify-content: center;
    gap: 8px;
    min-height: 0;
    min-width: 0;
    width: 100%;
}

.tank-container {
    flex: 0 0 auto;
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 0;
    min-width: 0;
    height: 100%;
}

.tank-wrapper {
    display: flex;
    flex-direction: row;
    align-items: stretch;
    height: 75%;
    max-width: 100%;
    gap: 3px;
}

.tank-body {
    aspect-ratio: 7 / 12;
    height: 100%;
    width: auto;
    min-width: 0;
    flex-shrink: 1;
    background-color: #e0e0e0;
    border-radius: 8px;
    border: 3px solid #ccc;
    position: relative;
    overflow: hidden;
    box-sizing: border-box;
}

.tank-scale {
    position: relative;
    height: calc(100% - 6px);
    align-self: center;
    min-width: 28px;
    flex-shrink: 0;
}

.scale-tick {
    position: absolute;
    right: 0;
    width: 100%;
    height: 1px;
    display: flex;
    align-items: center;
    justify-content: flex-start;
}

.scale-tick::before {
    content: '';
    display: block;
    width: 6px;
    height: 1px;
    background-color: #9EA1A2;
    margin-right: 2px;
}

.scale-label {
    color: #9EA1A2;
    line-height: 1;
    white-space: nowrap;
}

.tank-liquid {
    position: absolute;
    bottom: 0;
    left: 0;
    width: 100%;
    height: 0%;
    background-color: #EE7623;
    transition: height 0.5s ease-out, background-color 0.3s ease;
}

.tank-glass {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: linear-gradient(90deg, rgba(255, 255, 255, 0.1) 0%, rgba(255, 255, 255, 0.4) 30%, rgba(255, 255, 255, 0) 100%);
    pointer-events: none;
    z-index: 2;
}

.values-panel {
    flex: 0 1 auto;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: flex-start;
    gap: 6px;
    min-width: 0;
}

.value-block {
    display: flex;
    flex-direction: column;
    gap: 1px;
}

.value-label {
    color: #9EA1A2;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    line-height: 1.3;
    white-space: nowrap;
}

.value-number {
    font-weight: 700;
    line-height: 1.15;
    white-space: nowrap;
}

.available-value {
    color: #EE7623;
}

.occupied-value {
    color: #24272A;
}

.value-number .unit {
    font-weight: 400;
    color: #9EA1A2;
    margin-left: 2px;
}

.card-label {
    color: #9EA1A2;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    text-align: center;
    line-height: 1.3;
    flex-shrink: 0;
    white-space: nowrap;
}

.last-update {
    color: #9EA1A2;
    position: absolute;
    bottom: 4px;
    right: 8px;
    white-space: nowrap;
}

.layout-no-tank .tank-container {
    display: none;
}
.layout-no-tank .values-panel {
    align-items: center;
}
.layout-no-tank .value-block {
    align-items: center;
}

.layout-tiny .tank-container,
.layout-tiny .card-label,
.layout-tiny .last-update {
    display: none;
}
.layout-tiny .metric-card {
    padding: 4px 6px;
    gap: 0;
}
.layout-tiny .values-panel {
    flex-direction: row;
    align-items: center;
    justify-content: center;
    gap: 12px;
}
.layout-tiny .value-block {
    align-items: center;
}

.hide-scale .tank-scale {
    display: none;
}

.hide-label .card-label {
    display: none;
}

