self.onInit = function () {
    var scope = self.ctx.$scope;
    var settings = self.ctx.settings;

    scope.displayAvailable = '-';
    scope.displayOccupied = '-';
    scope.displayUnit = settings.customUnit || '';
    scope.label = settings.widgetLabel || '';
    scope.percentage = 0;
    scope.lastUpdate = '';
    scope.showScale = settings.showScale !== false;
    scope.scaleTicks = [];

    scope.liquidColor = settings.liquidColor || null;
    scope.tankColor = settings.tankColor || null;
    scope.cardBg = settings.backgraundCard || null;
    scope.borderColor = settings.borderColor || null;
    scope.availableColor = settings.availableColor || '#EE7623';
    scope.occupiedColor = settings.occupiedColor || '#24272A';

    scope.hasClickAction = false;
    scope.onCardClick = function () {};

    var clickActions = self.ctx.actionsApi.getActionDescriptors('cardClick');
    if (clickActions && clickActions.length > 0) {
        scope.hasClickAction = true;
        scope.onCardClick = function ($event) {
            var entityId = null;
            var entityName = null;
            var entityLabel = null;
            if (self.ctx.data && self.ctx.data.length > 0) {
                var ds = self.ctx.data[0].datasource;
                if (ds && ds.entity) {
                    entityId = ds.entity.id;
                    entityName = ds.entityName;
                    entityLabel = ds.entityLabel || ds.entityName;
                }
            }
            self.ctx.actionsApi.handleWidgetAction(
                $event, clickActions[0], entityId, entityName, null, entityLabel
            );
        };
    }

    self.applyLayoutClasses();
    self.buildScaleTicks();
    self.ctx.detectChanges();
}

self.buildScaleTicks = function () {
    var scope = self.ctx.$scope;
    var settings = self.ctx.settings;

    if (settings.showScale === false) {
        scope.scaleTicks = [];
        scope.showScale = false;
        return;
    }
    scope.showScale = true;

    var max = settings.maxValue || 100;
    var baseStep = settings.scaleStep || 10;
    if (baseStep <= 0) baseStep = 10;

    var scaleEl = self.ctx.$container[0].querySelector('.tank-scale');
    var scaleHeight = scaleEl ? scaleEl.clientHeight : 0;
    var step = self.calcAdaptiveStep(baseStep, max, scaleHeight);

    var ticks = [];
    for (var i = 0; i <= max; i += step) {
        var pct = (i / max) * 100;
        if (pct > 100) break;
        ticks.push({ pct: pct, label: i });
    }
    scope.scaleTicks = ticks;
}

self.calcAdaptiveStep = function (baseStep, max, availableHeight) {
    var minPxPerTick = 18;
    var totalTicks = Math.floor(max / baseStep) + 1;
    if (availableHeight <= 0 || totalTicks <= 2) return baseStep;

    var pxPerTick = availableHeight / (totalTicks - 1);
    var multiplier = 1;
    while (pxPerTick < minPxPerTick && multiplier < 32) {
        multiplier *= 2;
        var reduced = Math.floor(max / (baseStep * multiplier)) + 1;
        if (reduced <= 2) break;
        pxPerTick = availableHeight / (reduced - 1);
    }
    return baseStep * multiplier;
}

self.onDataUpdated = function () {
    var scope = self.ctx.$scope;
    var settings = self.ctx.settings;
    var rawValue = 0;
    var unit = '';

    if (self.ctx.defaultSubscription.data && self.ctx.defaultSubscription.data.length > 0) {
        var dataKey = self.ctx.defaultSubscription.data[0];
        if (dataKey.data && dataKey.data.length > 0) {
            var lastPoint = dataKey.data[dataKey.data.length - 1];
            rawValue = lastPoint[1];
        }
        if (!settings.customUnit && dataKey.dataKey.units) {
            unit = dataKey.dataKey.units;
        }
    }

    var numVal = (typeof rawValue === 'number') ? rawValue : parseFloat(rawValue);
    if (isNaN(numVal)) numVal = 0;

    var max = settings.maxValue || 100;
    var decimals = (typeof settings.decimals !== 'undefined') ? settings.decimals : 1;

    var occupied = numVal;
    var available = Math.max(max - numVal, 0);

    scope.displayOccupied = occupied.toFixed(decimals);
    scope.displayAvailable = available.toFixed(decimals);
    scope.displayUnit = settings.customUnit || unit;

    scope.percentage = Math.min(Math.max((numVal / max) * 100, 0), 100);

    if (settings.showLastUpdate) {
        var timestamp = null;
        if (self.ctx.defaultSubscription.data && self.ctx.defaultSubscription.data.length > 0) {
            var dk = self.ctx.defaultSubscription.data[0];
            if (dk.data && dk.data.length > 0) {
                timestamp = dk.data[dk.data.length - 1][0];
            }
        }
        if (timestamp) {
            var d = new Date(timestamp);
            scope.lastUpdate =
                String(d.getDate()).padStart(2, '0') + '/' +
                String(d.getMonth() + 1).padStart(2, '0') + '/' +
                String(d.getFullYear()).slice(-2) + ' ' +
                String(d.getHours()).padStart(2, '0') + ':' +
                String(d.getMinutes()).padStart(2, '0');
        } else {
            scope.lastUpdate = '';
        }
    } else {
        scope.lastUpdate = '';
    }

    self.ctx.detectChanges();
}

self.onResize = function () {
    self.applyLayoutClasses();
    self.buildScaleTicks();
    self.ctx.detectChanges();
}

self.applyLayoutClasses = function () {
    var el = self.ctx.$container[0].querySelector('.sensor-container');
    if (!el) return;
    var scope = self.ctx.$scope;
    var w = el.clientWidth;
    var h = el.clientHeight;

    el.classList.toggle('layout-tiny', h <= 80);
    el.classList.toggle('layout-no-tank', w <= 140);
    el.classList.toggle('hide-scale', w <= 220 || h <= 130);
    el.classList.toggle('hide-label', h <= 110);

    var sw = w / 300;
    var sh = h / 240;
    var s = Math.min(sw, sh);

    scope.availableFontSize = Math.max(12, Math.round(28 * s));
    scope.occupiedFontSize = Math.max(10, Math.round(19 * s));
    scope.unitFontSize = Math.max(7, Math.round(13 * s));
    scope.labelFontSize = Math.max(7, Math.round(11 * s));
    scope.smallLabelFontSize = Math.max(6, Math.round(10 * s));
    scope.scaleLabelFontSize = Math.max(6, Math.round(10 * s));
    scope.lastUpdateFontSize = Math.max(6, Math.round(9 * s));
}

self.typeParameters = function () {
    return {
        maxDatasources: 1,
        maxDataKeys: 1,
        dataKeysOptional: false
    };
}

self.actionSources = function () {
    return {
        'cardClick': {
            name: 'On Card Click',
            multiple: false
        }
    };
}

self.onDestroy = function () {
}

